import{_ as t,c as s,o as p,d as r}from"./app.262ed29e.js";var a="/assets/Dt9R7Y28PlI.1c7237d9.jpg",e="/assets/HfK9OntLIHU.2dfd8d19.jpg",o="/assets/k5tK7NpcOhg.9b17bd2c.jpg",_="/assets/LVDh13la6pM.522e438a.jpg",c="/assets/VE21n7wvp6M.fee6c23c.jpg",n="/assets/IMG_5247-1024x683.bb270460.jpg";const x='{"title":"\u041E\u0434\u0430 \u0430\u043A\u0440\u0438\u043B\u0443","description":"","frontmatter":{"title":"\u041E\u0434\u0430 \u0430\u043A\u0440\u0438\u043B\u0443","date":"2015-03-25","cover":"TZF769D0jCg.jpg"},"headers":[],"relativePath":"theory/research/oda-akrilu/index.md"}',i={},g=r('<p>\u041C\u044B \u0432\u0441\u0435 \u0446\u0435\u043D\u0438\u043C \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u043F\u043E\u0434\u0435\u043B\u043A\u0438, \u0432\u0435\u0449\u0438, \u043E\u0442\u0440\u0430\u0436\u0430\u044E\u0449\u0438\u0435 \u043D\u0430\u0448\u0435 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u043C\u0438\u0440\u0430 \u0438 \u043D\u0430\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435. \u041C\u043D\u043E\u0433\u0438\u0435 \u0438\u0437 \u043D\u0430\u0441 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0432\u044B\u0441\u043E\u043A\u043E \u0441\u0442\u0430\u0432\u044F\u0442 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E \u0438 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C. \u0415\u0441\u0442\u044C \u0442\u0435,\xA0\u043A\u0442\u043E \u0447\u0430\u0441\u0442\u0435\u043D\u044C\u043A\u043E \u0440\u0438\u0441\u0443\u0435\u0442, \u043F\u0440\u0438\u0434\u0443\u043C\u044B\u0432\u0430\u0435\u0442 \u0438\u0434\u0435\u0438, \u043F\u0440\u0438\u043B\u0430\u0433\u0430\u0435\u0442 \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u043E\u0434\u0445\u043E\u0434 \u043A \u0432\u0435\u0449\u0430\u043C \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u043E\u0441\u0442\u0438 \u0434\u0430\u0436\u0435 \u0432 \u0442\u0430\u043A\u0438\u0445 \u043C\u0435\u043B\u043E\u0447\u0430\u0445 \u043A\u0430\u043A \u0432\u044B\u0431\u043E\u0440 \u043E\u0434\u0435\u0436\u0434\u044B \u0438\u043B\u0438 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043A\u0430\u043A \u043F\u043E\u0432\u044F\u0437\u0430\u0442\u044C \u0448\u0430\u0440\u0444 \u0438\u043B\u0438 \u043D\u0430\u0434\u0432\u0438\u043D\u0443\u0442\u044C \u043D\u0430 \u043B\u043E\u0431 \u0448\u0430\u043F\u043A\u0443. \u041C\u043D\u0435 \u0445\u043E\u0447\u0435\u0442\u0441\u044F \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u0430\u0442\u044C \u0432\u0430\u043C \u043E \u043F\u0440\u043E\u0441\u0442\u043E\u043C \u0441\u043F\u043E\u0441\u043E\u0431\u0435 \u0440\u0430\u0441\u0448\u0438\u0440\u0438\u0442\u044C \u0441\u0432\u043E\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043E \u043F\u043E\u0434\u0435\u043B\u043A\u0430\u0445 \u0438 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u0445 \u0434\u0435\u043B\u0430\u0442\u044C \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0435 \u043D\u0430\u0441 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u0431\u043E\u043B\u0435\u0435 \u0436\u0438\u0432\u044B\u043C, \u0434\u0430\u0432\u0430\u0442\u044C \u0441\u0442\u0430\u0440\u044B\u043C \u0432\u0435\u0449\u0430\u043C \u0432\u0442\u043E\u0440\u043E\u0439 \u0448\u0430\u043D\u0441 \u0438 \u043F\u0440\u043E\u0441\u0442\u043E \u0437\u0430\u043D\u0438\u043C\u0430\u0442\u044C \u043F\u043E\u0440\u043E\u0439 \u043F\u0443\u0441\u0442\u043E\u0435 \u0438 \u043F\u0443\u0433\u0430\u044E\u0449\u0435\u0435 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u044B\u043C \u0437\u0430\u043D\u044F\u0442\u0438\u0435\u043C. <strong>\u0420\u0438\u0441\u043E\u0432\u0430\u0442\u044C \u0430\u043A\u0440\u0438\u043B\u043E\u043C \u043F\u043E \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u0430\u043C - \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u0435 \u0434\u0435\u043B\u043E!</strong> \u0417\u0432\u0443\u0447\u0438\u0442 \u043F\u0440\u043E\u0441\u0442\u043E \u0438, \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E, \u0441 \u043F\u0435\u0440\u0432\u043E\u0433\u043E \u0440\u0430\u0437\u0430 \u0434\u0430\u0436\u0435 \u0441\u043A\u0443\u0447\u043D\u043E. \u041D\u043E \u043F\u0440\u0438 \u0432\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0438 \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u0438 \u043C\u043E\u0436\u0435\u0442 \u0440\u043E\u0434\u0438\u0442\u044C\u0441\u044F \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0445 \u0438\u0434\u0435\u0439. \u0418\u0442\u0430\u043A, \u0435\u0433\u043E \u0432\u0435\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0430\u043A\u0440\u0438\u043B.</p><p><img src="'+a+'" alt=""></p><p>\u0410\u043A\u0440\u0438\u043B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043E\u0434\u043D\u043E\u0434\u0438\u0441\u043F\u0435\u0440\u0441\u043D\u043E\u0439 \u043A\u0440\u0430\u0441\u043A\u043E\u0439 \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u043F\u043E\u043B\u0438\u0430\u043A\u0440\u0438\u043B\u0430\u0442\u043E\u0432. \u0422\u0430\u043A\u0438\u0435 \u043A\u0440\u0430\u0441\u043A\u0438 \u043B\u0435\u0433\u043A\u043E \u0440\u0430\u0437\u0431\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432\u043E\u0434\u043E\u0439, \u043F\u043E\u0434\u0434\u0430\u044E\u0442\u0441\u044F \u0441\u043C\u0435\u0448\u0438\u0432\u0430\u043D\u0438\u044E, \u043F\u043E\u0441\u043B\u0435 \u0432\u044B\u0441\u044B\u0445\u0430\u043D\u0438\u044F \u043E\u043D\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0441\u0442\u043E\u0439\u043A\u0438\u043C\u0438 \u043A \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044E \u0432\u043E\u0434\u044B. \u041D\u0430\u043D\u043E\u0441\u0438\u0442\u044C \u043A\u0440\u0430\u0441\u043A\u0443 \u043C\u043E\u0436\u043D\u043E \u043A\u0430\u043A \u0432 \u0440\u0430\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u043C, \u0442\u0430\u043A \u0438 \u0432 \u0433\u0443\u0441\u0442\u043E\u043C \u043F\u0430\u0441\u0442\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438. \u0410\u043A\u0440\u0438\u043B \u0431\u044B\u0441\u0442\u0440\u043E \u0441\u043E\u0445\u043D\u0435\u0442, \u0447\u0442\u043E \u043E\u0447\u0435\u043D\u044C \u0443\u0434\u043E\u0431\u043D\u043E \u043F\u0440\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0438 \u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0438\u0445 \u0440\u0430\u0431\u043E\u0442, \u043D\u0430\u043D\u0435\u0441\u0435\u043D\u0438\u0438 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u0441\u043B\u043E\u0435\u0432, \u0434\u0430 \u0438 \u043F\u0440\u043E\u0441\u0442\u043E \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0440\u0438\u0441\u043E\u0432\u0430\u043D\u0438\u044F - \u043D\u0435 \u043D\u0443\u0436\u043D\u043E \u0441\u0442\u0440\u0430\u0448\u0438\u0442\u044C\u0441\u044F \u0437\u0430\u0434\u0435\u0442\u044C \u043B\u0430\u0434\u043E\u043D\u044C\u044E \u0438\u043B\u0438 \u0440\u0443\u043A\u043E\u0439 \u0435\u0449\u0435 \u043D\u0435 \u043F\u0440\u043E\u0441\u043E\u0445\u0448\u0438\u0439 \u0443\u0447\u0430\u0441\u0442\u043E\u043A.</p><p><img src="'+e+'" alt=""></p><p>\u041F\u0440\u0438 \u0432\u044B\u0441\u044B\u0445\u0430\u043D\u0438\u0438 \u0430\u043A\u0440\u0438\u043B\u043E\u0432\u044B\u0435 \u043A\u0440\u0430\u0441\u043A\u0438 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F \u0442\u0435\u043C\u043D\u0435\u0435, \u0438\u0445 \u0446\u0432\u0435\u0442 \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 \u043D\u0430\u0441\u044B\u0449\u0435\u043D\u043D\u044B\u0439 \u043E\u0442\u0442\u0435\u043D\u043E\u043A, \u0447\u0442\u043E \u043F\u043E\u0440\u0430\u0434\u0443\u0435\u0442 \u0433\u043B\u0430\u0437 \u043F\u0440\u0438\u0432\u044B\u043A\u0448\u0438\u0445 \u0440\u0438\u0441\u043E\u0432\u0430\u0442\u044C \u0430\u043A\u0432\u0430\u0440\u0435\u043B\u044C\u044E, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0442\u0430\u043A \u0438 \u043D\u043E\u0440\u043E\u0432\u0438\u0442 \u043F\u043E\u0431\u043B\u0435\u0434\u043D\u0435\u0442\u044C \u0438 \u0438\u0441\u0447\u0435\u0437\u043D\u0443\u0442\u044C \u0441 \u043B\u0438\u0441\u0442\u0430. <strong>\u0410\u043A\u0440\u0438\u043B \u043C\u043E\u0436\u0435\u0442\xA0\u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u0430\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432\u0430 \u043C\u0430\u0441\u043B\u044F\u043D\u043E\u0439 \u043A\u0440\u0430\u0441\u043A\u0435.</strong> \u0422\u0435\u043A\u0441\u0442\u0443\u0440\u0430 \u043F\u043E\u0441\u043B\u0435 \u043D\u0430\u043D\u0435\u0441\u0435\u043D\u0438\u044F \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442\u0441\u044F \u0440\u043E\u0432\u043D\u0430\u044F \u2014 \u0430\u043A\u0440\u0438\u043B\u043E\u0432\u044B\u0435 \u043A\u0440\u0430\u0441\u043A\u0438, \u0432 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u043C\u0430\u0441\u043B\u044F\u043D\u044B\u0445, \u043D\u0435 \u043E\u0431\u0440\u0430\u0437\u0443\u044E\u0442 \u0442\u0440\u0435\u0449\u0438\u043D. \u041B\u043E\u0436\u0438\u0442\u0441\u044F \u043A\u0440\u0430\u0441\u043A\u0430 \u043F\u043B\u0451\u043D\u043A\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0435\u043C\u043D\u043E\u0433\u043E \u0431\u043B\u0435\u0441\u0442\u0438\u0442, \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0437\u0430\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u044F \u0437\u0430\u043A\u0440\u0435\u043F\u0438\u0442\u0435\u043B\u044F\u043C\u0438 \u0438 \u043B\u0430\u043A\u0430\u043C\u0438 \u0438 \u0441\u043C\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u043B\u0435 \u0432\u044B\u0441\u044B\u0445\u0430\u043D\u0438\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0438\u0442\u0435\u043B\u044F\u043C\u0438. \u0425\u043E\u0442\u044F \u0441\u043E\u0441\u043A\u043E\u0431\u043B\u0438\u0442\u044C \u0441\u043B\u043E\u0439 \u043A\u0440\u0430\u0441\u043A\u0438 \u043D\u043E\u0433\u0442\u0435\u043C \u0438\u043B\u0438 \u0442\u0432\u0435\u0440\u0434\u044B\u043C \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043E\u043C \u0442\u0430\u043A\u0436\u0435 \u043D\u0435 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0442\u0440\u0443\u0434\u0430, \u043E\u0441\u043E\u0431\u0435\u043D\u043D\u043E \u0435\u0441\u043B\u0438 \u0432\u044B \u0431\u0443\u0434\u0435\u0442\u0435 \u0440\u0438\u0441\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u043F\u043B\u0430\u0441\u0442\u0438\u043A\u0435, \u0441\u0442\u0435\u043A\u043B\u0435 \u0438\u043B\u0438 \u043B\u044E\u0431\u043E\u0439 \u0434\u0440\u0443\u0433\u043E\u0439 \u0442\u0432\u0435\u0440\u0434\u043E\u0439 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438. \u0414\u0430, \u043F\u043E \u043F\u043E\u0432\u043E\u0434\u0443 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0435\u0439: \u0430\u043A\u0440\u0438\u043B\u043E\u0432\u044B\u0435 \u043A\u0440\u0430\u0441\u043A\u0438 \u0438 \u043B\u0430\u043A\u0438 \u043C\u043E\u0436\u043D\u043E \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u043B\u044E\u0431\u043E\u0439 \u043D\u0435\u0436\u0438\u0440\u043D\u043E\u0439 \u043E\u0441\u043D\u043E\u0432\u0435 \u0442\u0438\u043F\u0430 \u0441\u0442\u0435\u043A\u043B\u0430, \u0434\u0435\u0440\u0435\u0432\u0430, \u043C\u0435\u0442\u0430\u043B\u043B\u0430, \u043F\u043E\u043B\u043E\u0442\u043D\u0430, \u0445\u043E\u043B\u0441\u0442\u0430 \u0438 \u0442.\u0434.</p><p><img src="'+o+'" alt=""></p><p>\u0420\u0430\u0437\u043E\u0431\u0440\u0430\u0432\u0448\u0438\u0441\u044C \u0441 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430\u043C\u0438 \u044D\u0442\u043E\u0439 \u0447\u0443\u0434\u043E-\u043A\u0440\u0430\u0441\u043A\u0438 \u043D\u044B\u0440\u043D\u0435\u043C \u0432 \u0431\u0435\u0437\u0434\u043D\u0443 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0435\u0439, \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0443\u044E\u0441\u044F \u043F\u0435\u0440\u0435\u0434 \u043D\u0430\u043C\u0438 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E \u0441 \u043E\u0442\u043A\u0440\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u0431\u0430\u043D\u043E\u0447\u0435\u043A \u0441 \u0430\u043A\u0440\u0438\u043B\u043E\u043C. <strong>\u041F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043B\u044E\u0431\u043E\u0439 \u043F\u0440\u0435\u0434\u043C\u0435\u0442 \u0432\u0430\u0448\u0435\u0433\u043E \u043E\u0431\u0438\u0445\u043E\u0434\u0430 \u043C\u043E\u0436\u043D\u043E \u043F\u0440\u0435\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u0442\u044C \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u044D\u0442\u043E\u0433\u043E \u044F\u0440\u043A\u043E\u0433\u043E \u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u0430.</strong> \u0414\u043B\u044F \u043C\u0435\u043D\u044F \u043F\u0435\u0440\u0432\u044B\u043C\u0438 \u0448\u0430\u0433\u0430\u043C\u0438 \u043A \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044E, \u0447\u0442\u043E \u0440\u0438\u0441\u043E\u0432\u0430\u0442\u044C \u043C\u043E\u0436\u043D\u043E \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u0430 \u0431\u0443\u043C\u0430\u0433\u0435, \u0431\u044B\u043B\u043E \u0440\u0438\u0441\u043E\u0432\u0430\u043D\u0438\u0435 \u0430\u043A\u0440\u0438\u043B\u043E\u0432\u044B\u043C\u0438 \u043A\u0440\u0430\u0441\u043A\u0430\u043C\u0438 \u043D\u0430 \u043E\u0434\u0435\u0436\u0434\u0435. \u041D\u0430\u0447\u0438\u043D\u0430\u043B\u043E\u0441\u044C \u0432\u0441\u0435 \u0441 \u0434\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u043F\u0440\u043E\u0441\u0442\u044B\u0445 \u043D\u0430\u0434\u043F\u0438\u0441\u0435\u0439 \u043D\u0430 \u0444\u0443\u0442\u0431\u043E\u043B\u043A\u0430\u0445 \u0432 \u043F\u043E\u0434\u0430\u0440\u043E\u043A \u0434\u0440\u0443\u0437\u044C\u044F\u043C, \u0447\u0442\u043E \u0437\u0430\u0442\u0435\u043C \u043F\u0435\u0440\u0435\u0440\u043E\u0441\u043B\u043E \u0432 \u0438\u0434\u0435\u044E \u043F\u0435\u0440\u0435\u043D\u0435\u0441\u0435\u043D\u0438\u044F \u0431\u043E\u043B\u0435\u0435 \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u043A\u0430\u0440\u0442\u0438\u043D\u043E\u043A \u043D\u0430 \u0442\u043A\u0430\u043D\u044C. \u0418\u043D\u043E\u0433\u0434\u0430 \u043D\u0430 \u043F\u043E\u043C\u043E\u0449\u044C \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u043B\u0438 \u0441\u0430\u043C\u043E\u0434\u0435\u043B\u044C\u043D\u044B\u0435 \u0442\u0440\u0430\u0444\u0430\u0440\u0435\u0442\u044B, \u0438\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043F\u0440\u0438\u043D\u0442\u0435\u0440\u0430 \u0438 \u043D\u043E\u0436\u043D\u0438\u0446. \u0412 \u0446\u0435\u043B\u043E\u043C \u043B\u044E\u0431\u043E\u0439 \u0443\u0433\u043E\u0434\u043D\u044B\u0439 \u0432\u0430\u043C \u0440\u0438\u0441\u0443\u043D\u043E\u043A, \u0434\u0430\u0436\u0435 \u043D\u0435\u0431\u0440\u0435\u0436\u043D\u044B\u0439 \u043D\u0430\u0431\u0440\u043E\u0441\u043E\u043A \u043E\u0442 \u0440\u0443\u043A\u0438, \u043F\u043E\u0437\u0432\u043E\u043B\u0438\u0442 \u043E\u0436\u0438\u0442\u044C \u0441\u0442\u0430\u0440\u043E\u0439 \u0444\u0443\u0442\u0431\u043E\u043B\u043A\u0435, \u0441\u043F\u0440\u044F\u0442\u0430\u0442\u044C \u043F\u044F\u0442\u043D\u043E \u043D\u0430 \u0432\u0438\u0434\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435 \u0438\u043B\u0438 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u0440\u043E\u0441\u0442\u043E \u0438\u0437\u0431\u0430\u0432\u0438\u0442 \u043E\u0442 \u0441\u043A\u0443\u043A\u0438.</p><p><img src="'+_+'" alt=""></p><p>\u0420\u0438\u0441\u043E\u0432\u0430\u0442\u044C \u043D\u0430 \u0442\u043A\u0430\u043D\u0438 \u043D\u0435 \u0441\u043B\u043E\u0436\u043D\u043E, \u0432\u0430\u0436\u043D\u043E \u043B\u0438\u0448\u044C \u043F\u043E\u0434\u043B\u043E\u0436\u0438\u0442\u044C \u043F\u043E\u0434 \u0441\u043B\u043E\u0439, \u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0440\u0438\u0441\u0443\u0435\u0448\u044C, \u0431\u0443\u043C\u0430\u0433\u0443, \u0447\u0442\u043E\u0431\u044B \u043A\u0440\u0430\u0441\u043A\u0430 \u043D\u0435 \u043E\u0442\u043F\u0435\u0447\u0430\u0442\u0430\u043B\u0430\u0441\u044C \u043D\u0430 \u0441\u043F\u0438\u043D\u043A\u0435 \u0444\u0443\u0442\u0431\u043E\u043B\u043A\u0438 \u0438\u043B\u0438 \u0441\u0442\u043E\u043B\u0435. \u041A\u0440\u0430\u0441\u043A\u0443 \u043B\u0443\u0447\u0448\u0435 \u043A\u043B\u0430\u0441\u0442\u044C \u0433\u0443\u0441\u0442\u044B\u043C \u0441\u043B\u043E\u0435\u043C, \u0442\u0430\u043A \u043A\u0430\u043A \u043F\u0440\u0438 \u0432\u044B\u0441\u044B\u0445\u0430\u043D\u0438\u0438 \u043C\u043E\u0433\u0443\u0442 \u043E\u0431\u0440\u0430\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C\u0441\u044F &quot;\u0434\u044B\u0440\u043E\u0447\u043A\u0438&quot; \u0438 \u0437\u0430\u0437\u043E\u0440\u044B \u0437\u0430 \u0441\u0447\u0435\u0442 \u0442\u0435\u043A\u0441\u0442\u0443\u0440\u044B \u0442\u043A\u0430\u043D\u0435\u0432\u043E\u0433\u043E \u043F\u043E\u043B\u043E\u0442\u043D\u0430.</p><p>\u0415\u0449\u0435 \u043E\u0434\u043D\u0438\u043C \u0437\u0430\u043D\u044F\u0442\u043D\u044B\u043C \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u043E\u043C \u0431\u0443\u0434\u0435\u0442 \u0440\u0430\u0437\u0440\u0438\u0441\u043E\u0432\u0430\u0442\u044C \u0447\u0435\u0445\u043E\u043B \u0434\u043B\u044F \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0430. \u041F\u0440\u0438\u0434\u0443\u043C\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u043E\u0431\u0440\u0430\u0437, \u043F\u0435\u0440\u0435\u043D\u0435\u0441\u0442\u0438 \u043F\u043E\u043D\u0440\u0430\u0432\u0438\u0432\u0448\u0435\u0435\u0441\u044F \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435, \u043E\u0442\u043C\u0435\u0442\u0438\u0442\u044C \u0437\u043D\u0430\u043A\u043E\u043C \u0438\u043B\u0438 \u0441\u0438\u043C\u0432\u043E\u043B\u043E\u043C \u043F\u0440\u0435\u0434\u043C\u0435\u0442, \u043C\u0430\u044F\u0447\u0430\u0449\u0438\u0439 \u043F\u0435\u0440\u0435\u0434 \u0433\u043B\u0430\u0437\u0430\u043C\u0438 \u0432\u0441\u0451 \u0432\u0440\u0435\u043C\u044F,\xA0\u2014\xA0\u044D\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0438\u043C\u0435\u0442\u044C \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043C\u044B\u0441\u043B.</p><p><img src="'+c+'" alt=""></p><p>\u0412 \u0434\u0430\u043D\u043D\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 \u043B\u0443\u0447\u0448\u0435 \u043D\u0430\u043D\u0435\u0441\u0442\u0438 \u043D\u0430 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u044C \u043F\u043B\u0430\u0441\u0442\u0438\u043A\u043E\u0432\u043E\u0433\u043E \u0447\u0435\u0445\u043B\u0430 \u0441\u043D\u0430\u0447\u0430\u043B\u0430 \u0430\u043A\u0440\u0438\u043B\u043E\u0432\u044B\u0439 \u0433\u0440\u0443\u043D\u0442, \u0447\u0442\u043E\u0431\u044B \u0430\u043A\u0440\u0438\u043B \u043B\u043E\u0436\u0438\u043B\u0441\u044F \u0440\u043E\u0432\u043D\u0435\u0435 \u0438 \u0434\u0435\u0440\u0436\u0430\u043B\u0441\u044F \u043A\u0440\u0435\u043F\u0447\u0435. \u0410 \u0434\u0430\u043B\u044C\u0448\u0435 \u0434\u0435\u043B\u043E \u0437\u0430 \u044D\u0441\u043A\u0438\u0437\u043E\u043C \u0438 \u043A\u0440\u0430\u0441\u043A\u043E\u0439. <strong>\u0413\u043E\u0442\u043E\u0432\u044B\u0439 \u0440\u0438\u0441\u0443\u043D\u043E\u043A \u0441\u0442\u043E\u0438\u0442 \u043F\u043E\u043A\u0440\u044B\u0442\u044C \u043B\u0430\u043A\u043E\u043C.</strong> \u0425\u043E\u0442\u044C \u0430\u043A\u0440\u0438\u043B \u0438 \u043A\u0440\u0435\u043F\u043A\u0438\u0439 \u043C\u0430\u043B\u044B\u0439, \u0440\u0435\u0433\u0443\u043B\u044F\u0440\u043D\u043E\u0435 \u0435\u0440\u0437\u0430\u043D\u044C\u0435 \u0432 \u043A\u0430\u0440\u043C\u0430\u043D\u0430\u0445, \u043F\u043E\u043F\u0430\u0434\u0430\u043D\u0438\u0435 \u0432 \u0440\u0443\u043A\u0438, \u0432\u043E\u0434\u0443, \u0443\u0434\u0430\u0440\u044B \u043E \u0441\u0442\u043E\u043B\u0435\u0448\u0438\u0446\u044B, \u043A\u043B\u044E\u0447\u0438 \u0432 \u0441\u0443\u043C\u043A\u0430\u0445 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u044F \u0441\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u0431\u0443\u0434\u0443\u0442 \u043D\u0430\u043D\u043E\u0441\u0438\u0442\u044C \u0443\u0449\u0435\u0440\u0431 \u0432\u0430\u0448\u0435\u043C\u0443\xA0\u0440\u0438\u0441\u0443\u043D\u043A\u0443. \u041B\u0430\u043A \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0437\u0430\u0449\u0438\u0442\u0438\u0442. \u0425\u043E\u0440\u043E\u0448\u043E \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 \u044F\u0445\u0442\u043D\u044B\u0439 \u043B\u0430\u043A \u0432 \u0430\u044D\u0440\u043E\u0437\u043E\u043B\u044C\u043D\u044B\u0445 \u0431\u0430\u043B\u043B\u043E\u043D\u0430\u0445 \u0438\u043B\u0438 \u0432 \u0431\u0430\u043D\u043A\u0430\u0445, \u043D\u0430\u043D\u043E\u0441\u0438\u043C\u044B\u0439 \u043A\u0438\u0441\u0442\u044C\u044E. \u041E\u0434\u043D\u043E\u0433\u043E-\u0434\u0432\u0443\u0445 \u0441\u043B\u043E\u0435\u0432 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E. \u0414\u0440\u0443\u0433\u043E\u0433\u043E \u0442\u0430\u043A\u043E\u0433\u043E \u0447\u0435\u0445\u043B\u0430 \u0434\u043B\u044F \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0430 \u0442\u043E\u0447\u043D\u043E \u043D\u0435 \u0431\u0443\u0434\u0435\u0442. \u041F\u0440\u0435\u0434\u043C\u0435\u0442\u044B \u043C\u0435\u0431\u0435\u043B\u0438 \u0442\u0430\u043A \u0436\u0435 \u0438\u043C\u0435\u044E\u0442 \u043F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B \u0440\u043E\u0441\u043F\u0438\u0441\u0438 \u0430\u043A\u0440\u0438\u043B\u043E\u043C, \u043E\u0431 \u043E\u0434\u043D\u043E \u0442\u0430\u043A\u043E\u043C \u0438\u0437\u0434\u0435\u043B\u0438\u0438 \u043C\u044B \u0443\u0436\u0435 \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u043B\u0438 \u0440\u0430\u043D\u0435\u0435 \u0432 \u043D\u0430\u0448\u0435\u0439 <a href="/practice/project/mandala/" title="\u0422\u0430\u0431\u0443\u0440\u0435\u0442\u043A\u0430 \u0441 \u043C\u0430\u043D\u0434\u0430\u043B\u043E\u0439 \u043D\u0430 \u0441\u0438\u0434\u0435\u043D\u044C\u0438">\u043F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u0438 \u043F\u0440\u043E \u0442\u0430\u0431\u0443\u0440\u0435\u0442\u043A\u0443-\u043C\u0430\u043D\u0434\u0430\u043B\u0443</a>.</p><p><img src="'+n+'" alt=""></p><p>\u0417\u043D\u0430\u044F \u043E \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u0438 \u0430\u043A\u0440\u0438\u043B\u0430 \u0443\u043A\u0440\u044B\u0432\u0430\u0442\u044C \u0438 \u0440\u0430\u0437\u0440\u0438\u0441\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u043B\u044E\u0431\u044B\u0435 \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438 \u043C\u043E\u0436\u043D\u043E \u0442\u0435\u043F\u0435\u0440\u044C \u043E\u0442\u043E\u0440\u0432\u0430\u0442\u044C \u0432\u0437\u0433\u043B\u044F\u0434 \u043E\u0442 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0430, \u043E\u0433\u043B\u044F\u043D\u0443\u0442\u044C\u0441\u044F \u0432\u043E\u043A\u0440\u0443\u0433 \u0438 \u043D\u0435\u043E\u0436\u0438\u0434\u0430\u043D\u043D\u043E \u0434\u043B\u044F \u0441\u0435\u0431\u044F \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u044C \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u0441\u0435\u0433\u043E \u0432\u043E\u043A\u0440\u0443\u0433 \u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0440\u0438\u0441\u043E\u0432\u0430\u0442\u044C. <strong>\u041D\u0430\u0441 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0442 \u0445\u043E\u043B\u0441\u0442\u044B!</strong> \u0418 \u043C\u044B \u043C\u043E\u0436\u0435\u043C \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0432 \u0441\u0435\u0431\u0435 \u043E\u0433\u043E\u043D\u0435\u043A \u0442\u0432\u043E\u0440\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0432\u0437\u0433\u043B\u044F\u0434\u0430 \u043D\u0430 \u043C\u0438\u0440, \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u0440\u0443\u044F \u0438 \u043F\u0435\u0440\u0435\u043D\u043E\u0441\u044F \u0441\u0432\u043E\u0438 \u0444\u0430\u043D\u0442\u0430\u0437\u0438\u0438 \u043D\u0430 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u0435 \u043D\u0430\u0441 \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u044B \u0431\u0435\u0437 \u043E\u0441\u043E\u0431\u043E\u0433\u043E \u0442\u0440\u0443\u0434\u0430, \u0434\u0430\u0436\u0435, \u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u2014\xA0\u0441 \u0443\u0434\u043E\u0431\u0441\u0442\u0432\u043E\u043C. \u0418 \u0447\u0430\u0441\u0442\u043E \u043D\u0435 \u043D\u0443\u0436\u043D\u043E \u043F\u043E\u043A\u0443\u043F\u0430\u0442\u044C \u043D\u0438\u0447\u0435\u0433\u043E \u043D\u043E\u0432\u043E\u0433\u043E, \u0438\u0441\u043A\u0430\u0442\u044C \u0437\u0430\u043C\u044B\u0441\u043B\u043E\u0432\u0430\u0442\u043E\u0435, \u0432\u044B\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u0442\u044C \u043D\u0430\u0434\u043E\u0435\u0432\u0448\u0435\u0435. \u0414\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043F\u043E\u0432\u0435\u0440\u0438\u0442\u044C \u0432 \u0441\u0435\u0431\u044F, \u0432\u0437\u044F\u0442\u044C \u0432 \u0440\u0443\u043A\u0438 \u043A\u0438\u0441\u0442\u044C \u0438 \u043D\u0430\u0431\u043E\u0440 \u043A\u0440\u0430\u0441\u043E\u043A \u0438 \u0434\u0430\u0442\u044C \u0432\u043E\u043B\u044E \u043F\u043E\u0440\u044B\u0432\u0443 \u043D\u0430\u043C\u0430\u0437\u0430\u0442\u044C \u043A\u0440\u0430\u0441\u043A\u043E\u0439 \u043A\u0430\u043A\u043E\u0439-\u043D\u0438\u0431\u0443\u0434\u044C \u0440\u0438\u0441\u0443\u043D\u043E\u043A. \u0412\u0441\u0435 \u043C\u044B\xA0\u044D\u0442\u043E \u043C\u043E\u0436\u0435\u043C.</p><p><strong>\u0410\u043A\u0440\u0438\u043B\u043E\u0432\u044B\u0445 \u0432\u0430\u043C \u0441\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0439!</strong></p>',15),d=[g];function l(m,f,v,h,j,u){return p(),s("div",null,d)}var D=t(i,[["render",l]]);export{x as __pageData,D as default};
